def tarjan_scc(num_nodes, adj_list):
    ids = [-1] * num_nodes
    low = [-1] * num_nodes
    on_stack = [False] * num_nodes
    stack = []
    sccs = []
    time = 0

    def dfs(u):
        nonlocal time

        ids[u] = low[u] = time
        time += 1
        stack.append(u)
        on_stack[u] = True

        for v in adj_list[u]:
            if ids[v] == -1:
                dfs(v)
                low[u] = min(low[u], low[v])
            elif on_stack[v]:
                low[u] = min(low[u], ids[v])

        if ids[u] == low[u]:
            current_scc = []
            while True:
                node = stack.pop()
                on_stack[node] = False
                current_scc.append(node)
                if node == u:
                    break
            sccs.append(current_scc)

    for i in range(num_nodes):
        if ids[i] == -1:
            dfs(i)

    return sccs
